    int y0 = center.GetY();

    int x = radius - 1;
    int y = 0;
    int tx = 1;
    int ty = 1;
    int error = tx - (radius << 1);

    while (x >= y) {
        // Render the points directly using SDL_RenderDrawPoint.
        SDL_RenderDrawPoint(renderer, x0 + x, y0 - y);
        SDL_RenderDrawPoint(renderer, x0 + x, y0 + y);
        // ... Render the other points using symmetry ...

        if (error <= 0) {
            ++y;
            error += ty;
            ty += 2;
